  (SELECT id FROM public.tours WHERE slug = 'south-jeju-classic-bus-tour' LIMIT 1),
  'South Jeju Waterfall, Cliff, Tea & Hallasan Bus Day Tour',
  'Waterfall, sea stack, basalt cliffs, tea fields, and a short Hallasan walk in one classic value route.',
  'South & Southwest Jeju',
  '10 hours',
