  '{"document_kind":"tour_product_full_page_v1","schema_version":1,"slug":"south-jeju-classic-bus-tour","locale":"zh-TW","product_id":"south-jeju-classic-bus-tour","seo":{"pageTitle":"South Jeju Waterfall, Cliff, Tea & Hallasan Bus Day Tour | AtoC Korea","metaDescription":"A classic South Jeju bus day tour covering Cheonjiyeon Waterfall, Oedolgae, Jusangjeolli Cliff, O’sulloc Tea Museum, and the Eoseungsaengak trail area. A strong value route for first-time visitors who want Jeju’s south-side highlights in one day."},"catalog_card":{"slug":"south-jeju-classic-bus-tour","title":"South Jeju Waterfall, Cliff, Tea & Hallasan Bus Day Tour","subtitle":"Waterfall, sea stack, basalt cliffs, tea fields, and a short Hallasan walk in one classic value route.","region":"South & Southwest Jeju","duration":"10 hours","stopsCount":6,"rating":4.7,"reviewCount":89,"badges":["Best-Value Bus Tour","Classic South Jeju Route","First-Time Friendly"],"heroImage":"https://api.cdn.visitjeju.net/photomng/imgpath/202202/10/fd98aff8-eede-4448-add5-4b412d2ddf56.webp","thumbnail":"https://api.cdn.visitjeju.net/photomng/thumbnailpath/202202/10/8eaffb2c-b26b-4b3f-88b8-4cae84a95d96.webp","priceLabel":"From US$49 per person","shortCardDescription":"A full-day South Jeju bus route that connects a waterfall walk, coastal rock scenery, basalt cliffs, a relaxed lunch break, tea culture, and a short Hallasan-side trail. It is built for travelers who want strong sightseeing coverage with a lower price barrier."},"headlineLine1":"South Jeju Waterfall, Cliff, Tea","headlineLine2":"and Hallasan Bus Day Tour","price":{"amountLabel":"49","currency":"USD","per":"person"},"hero":{"imageUrl":"https://api.cdn.visitjeju.net/photomng/imgpath/202202/10/fd98aff8-eede-4448-add5-4b412d2ddf56.webp","imagePosition":"center 48%","tagline":"From a shaded waterfall path and dramatic sea cliffs to green tea fields and a short Hallasan-side ascent, this classic Jeju bus route delivers strong variety at a practical price point.","pills":["Classic South Jeju","Bus Day Tour","Best Value"],"meta":{"duration":"9 hours","region":"South & Southwest Jeju","stops":"5 stops","rating":4.7,"ratingStars":4}},"subnavItems":[{"id":"overview","label":"Overview"},{"id":"itinerary","label":"Itinerary"},{"id":"details","label":"Details"},{"id":"faq","label":"FAQ"},{"id":"reviews","label":"Reviews"}],"glanceItems":[{"icon":"camera","label":"Photo Potential","value":"High"},{"icon":"mountain","label":"Scenery Density","value":"High"},{"icon":"footprints","label":"Walking Difficulty","value":"Moderate"},{"icon":"cloud-rain","label":"Rain Suitability","value":"Low to Moderate"},{"icon":"users","label":"Family Suitability","value":"Good"},{"icon":"gauge","label":"Pace","value":"Full but Manageable"}],"galleryItems":[{"id":1,"type":"photo","src":"https://api.cdn.visitjeju.net/photomng/imgpath/202202/10/fd98aff8-eede-4448-add5-4b412d2ddf56.webp","location":"Hallasan 1100 Area","atmosphere":"A cooler mountain-side contrast to the coast-heavy first half","alt":"Road 1100 and Hallasan-side scenery near Eoseungsaengak in Jeju"},{"id":2,"type":"photo","src":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=1200&q=80","location":"Cheonjiyeon Waterfall","atmosphere":"A shaded green opening with moving water and a softer start","alt":"Waterfall path atmosphere for a South Jeju day tour"},{"id":3,"type":"photo","src":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=1200&q=80","location":"Oedolgae Coast","atmosphere":"Open sea wind and volcanic rock scenery","alt":"Coastal viewpoint mood on a South Jeju bus day tour"},{"id":4,"type":"photo","src":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","location":"Jusangjeolli Cliff","atmosphere":"Jeju’s signature basalt geometry over the sea","alt":"Basalt cliff scenery similar to Jusangjeolli on Jeju Island"},{"id":5,"type":"photo","src":"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=1200&q=80","location":"O’sulloc Tea Museum","atmosphere":"A calmer, greener reset with tea-field atmosphere","alt":"Tea museum and green tea field atmosphere in Jeju"}],"itineraryStops":[{"number":1,"time":"09:50","duration":"45 min","name":"Cheonjiyeon Waterfall","category":"Waterfall Walk","description":"Cheonjiyeon works well as a gentle opening stop. The paved path, shade, and waterfall setting ease travelers into the day before the route shifts into more exposed coastal scenery and longer drive segments.","image":"https://images.unsplash.com/photo-1506744038136-46273834b3fb?w=1200&q=80","highlights":["A classic South Jeju waterfall stop with an easy scenic approach","Shaded path and greenery create a softer opening rhythm","Stronger on atmosphere than pure activity","Good early-stop photo value without heavy physical demand"],"timeUsed":["Arrival briefing and short walk in","Waterfall viewing and photo time","Return to the vehicle and regroup"],"whyOnRoute":"Starting here gives the day a calmer opening before moving into wind-exposed coastline viewpoints and the longer cross-island drive toward O’sulloc and Hallasan.","visitBasics":{"hours":"09:00–22:00 (night operation partially suspended through May 31, 2026)","closed":"Open year-round","admission":"KRW 2,000 adults / KRW 1,000 youth and children","walking":"Easy"},"convenience":{"restroom":"Near the entrance area","parking":"Parking available"},"smartNotes":{"photo":"The waterfall itself lands best with vertical framing, while the tree-lined path works better for wider atmosphere shots.","facilities":"Facilities are straightforward and easy to use at the start of the day.","tip":"This stop is more about a comfortable scenic opening than speed-walking to maximize minutes."}},{"number":2,"time":"10:50","duration":"35 min","name":"Oedolgae","category":"Coastal Sea Stack Viewpoint","description":"Oedolgae is a short but visually strong stop. The sea stack, cliff line, and open southern coastline give the route a quick change of mood after the shaded waterfall approach.","image":"https://images.unsplash.com/photo-1469474968028-56623f02e42e?w=1200&q=80","highlights":["One of South Jeju’s best short-stop coastal viewpoints","Strong open-sea framing with relatively little time needed","Works well on bus itineraries because the visual reward is fast","Adds variety without requiring a long trek"],"timeUsed":["Short walk from parking to the main viewpoint","Viewing and photo stop","Regroup and depart"],"whyOnRoute":"It keeps momentum high between the waterfall opening and the more structured ticketed stop at Jusangjeolli Cliff.","visitBasics":{"hours":"Open 24 hours","closed":"Open year-round","admission":"Free","walking":"Easy to moderate"},"convenience":{"restroom":"Available near the entrance area","parking":"Free parking available"},"smartNotes":{"photo":"Because wind and backlight can be strong, side angles and wide coastal framing usually look better than tight centered shots.","facilities":"Facilities are simple rather than extensive.","tip":"This is a high-reward short stop, so the route should keep the visit tight rather than stretching it too long."}},{"number":3,"time":"11:45","duration":"40 min","name":"Jusangjeolli Cliff","category":"Basalt Cliff Landmark","description":"Jusangjeolli is one of the clearest visual expressions of Jeju’s volcanic geology. The hexagonal basalt columns and ocean backdrop make it one of the route’s most instantly recognizable landmarks.","image":"https://images.unsplash.com/photo-1518509562904-e7ef99cdcc86?w=1200&q=80","highlights":["One of Jeju’s most iconic volcanic coastal sights","Strong payoff for first-time visitors seeking signature scenery","High photo value with a short viewing loop","A clean landmark stop that reads well even on a bus format"],"timeUsed":["Entry and short walking approach","Main viewing platform stop","Photo time and regroup"],"whyOnRoute":"This is the route’s strongest iconic geology stop, so it works best before the more relaxed tea-field section and mountain-side finish.","visitBasics":{"hours":"09:00–18:00 (last entrance 17:40)","closed":"Open year-round","admission":"KRW 2,000 adults / KRW 1,000 children and youth","walking":"Easy to moderate"},"convenience":{"restroom":"At or near the visitor area","parking":"Paid parking lot available"},"smartNotes":{"photo":"The basalt pattern reads best when the ocean is left in frame rather than cropping too tightly on the rocks alone.","facilities":"This is a straightforward sightseeing stop with solid access but limited shade.","tip":"Wind and sea spray can shape the comfort level here more than raw walking distance."}},{"number":4,"time":"12:35","duration":"60 min","name":"Lunch Break (Free Choice)","category":"Free Lunch Time","description":"This free lunch break gives travelers a practical reset after Jusangjeolli Cliff. It keeps the route flexible for different tastes and budgets, while making it clear that meal costs are not included in the tour price.","image":"https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=1200&q=80","highlights":["One full hour for a relaxed meal stop","Flexible free-choice lunch rather than a fixed set menu","Works well for mixed traveler preferences","Meal cost is not included"],"timeUsed":["Guide drop-off and lunch area briefing","Free lunch time","Regroup and departure"],"whyOnRoute":"Placing lunch after Jusangjeolli creates a more natural sightseeing rhythm before the route continues west toward O’sulloc and then returns uphill toward Hallasan.","visitBasics":{"hours":"Depends on the day’s restaurant area and traffic flow","closed":"Varies by restaurant","admission":"Meal cost not included","walking":"Easy"},"convenience":{"restroom":"Available at or near the lunch stop","parking":"Bus-accessible stop used by the guide"},"smartNotes":{"photo":"This is mainly a practical reset stop rather than a photo-driven sightseeing stop.","facilities":"Facilities depend on the restaurant zone selected that day.","tip":"Because lunch is free choice and not included, travelers can choose based on appetite, speed, and budget."}},{"number":5,"time":"14:10","duration":"60 min","name":"O’sulloc Tea Museum","category":"Tea Culture and Greenery","description":"After three scenic outdoor stops, O’sulloc resets the day. It brings in tea-field views, indoor museum space, café energy, and a more relaxed walking pattern before the route climbs back toward Hallasan.","image":"https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=1200&q=80","highlights":["A calmer mixed indoor-outdoor stop in the middle of a scenery-heavy day","Tea-field visuals add a different texture from cliffs and coastline","Good for café time, souvenirs, and a short reset","One of the route’s best rain-buffer stops"],"timeUsed":["Museum and tea-field orientation","Free time for museum browsing, café, or gift shop","Regroup before departure"],"whyOnRoute":"This is the best point in the day to slow the pace down and give the route a different sensory tone before the final Hallasan-side segment.","visitBasics":{"hours":"09:00–18:00","closed":"Open year-round","admission":"Free (some experience programs cost extra)","walking":"Easy"},"convenience":{"restroom":"Inside the museum complex","parking":"Parking available"},"smartNotes":{"photo":"Tea fields, glass reflections, and dessert presentation all work well here, but the stop usually feels best when it is not overpacked with shopping time.","facilities":"Among today’s stops, this one gives the strongest indoor and café support.","tip":"On rainy or windy days, this stop often becomes more valuable than it looks on paper."}},{"number":6,"time":"16:10","duration":"70 min","name":"Eoseungsaengak","category":"Short Hallasan-Side Trail","description":"Eoseungsaengak adds a light mountain element without turning the day into a full trekking itinerary. It is short in distance, but the stairs and uphill sections still make it the most physically demanding stop of the route.","image":"https://api.cdn.visitjeju.net/photomng/imgpath/202202/10/fd98aff8-eede-4448-add5-4b412d2ddf56.webp","highlights":["A short Hallasan-side climb with broad views on clear days","Adds altitude and mountain atmosphere to a coast-heavy route","Short enough for a day tour, but still feels rewarding","The strongest active segment on the itinerary"],"timeUsed":["Trail briefing and pace guidance","Ascent and summit-area viewing depending on group condition","Descent, regroup, and departure"],"whyOnRoute":"Ending with Eoseungsaengak gives the route a cleaner final rise in energy after the calmer O’sulloc stop, instead of flattening out into one more passive viewpoint.","visitBasics":{"hours":"Trail entry cutoff varies by season; Eorimok entry is controlled by Hallasan National Park","closed":"Subject to weather and safety controls","admission":"Free","walking":"Moderate, with stairs and short uphill sections"},"convenience":{"restroom":"At the trailhead facilities","parking":"Parking available near the entry area"},"smartNotes":{"photo":"Wide summit-side views work best in clear weather, but the route itself can also produce strong forest and stair-line shots.","facilities":"Facilities are centered at the trailhead rather than along the climb.","tip":"This is not a long hike, but it is still the stop most likely to separate faster and slower walkers."}}],"routeFlowStops":[{"id":"01","name":"Cheonjiyeon","theme":"Waterfall"},{"id":"02","name":"Oedolgae","theme":"Coast"},{"id":"03","name":"Jusangjeolli","theme":"Basalt"},{"id":"04","name":"O’sulloc","theme":"Tea"},{"id":"05","name":"Eoseungsaengak","theme":"Hallasan"}],"routePhases":[{"label":"Morning","range":"1-3","theme":"Waterfall to South-Coast Landmarks","bgClass":"bg-sky-50/70","textClass":"text-sky-700","dotClass":"bg-sky-500"},{"label":"Midday","range":"4","theme":"Tea-Field Reset","bgClass":"bg-emerald-50/70","textClass":"text-emerald-700","dotClass":"bg-emerald-500"},{"label":"Late Afternoon","range":"5","theme":"Hallasan-Side Finish","bgClass":"bg-amber-50/70","textClass":"text-amber-700","dotClass":"bg-amber-500"}],"routeShapeIntro":{"title":"How the day flows","subtitle":"The route opens with a shaded waterfall walk, moves through South Jeju’s coastal landmarks, slows down at O’sulloc, and finishes with a short Hallasan-side trail. Pickup runs from 08:30 to 09:05 in Jeju City, with return usually around 17:30 to 18:10."},"whyTourWorks":{"bestFor":["First-time visitors to Jeju","Travelers who want a lower price barrier","Couples","Adult families","Visitors who want both coast and a short mountain walk in one day"],"lessIdeal":["Travelers avoiding stairs or uphill walking","Families relying heavily on strollers","Travelers who want a slow luxury pace","Anyone seeking a mostly indoor or rain-proof route"],"routeLogicSections":[{"title":"Why this bus route works well","icon":"bus","iconBg":"bg-sky-50/80","iconColor":"text-sky-600","items":[{"label":"High sightseeing coverage for the price","detail":"The route gives first-time visitors a strong South Jeju overview without the price jump of a private format."},{"label":"Shorter scenic stops make the bus format efficient","detail":"Oedolgae and Jusangjeolli both deliver strong visual reward without demanding long on-site time."},{"label":"The stop mix avoids feeling repetitive","detail":"Waterfall, sea stack, basalt coast, tea fields, and a mountain-side trail all give the day clearly different moods."}]},{"title":"How the walking load actually feels","icon":"footprints","iconBg":"bg-amber-50/80","iconColor":"text-amber-600","items":[{"label":"Mostly manageable, with one clear active stop","detail":"Cheonjiyeon, Oedolgae, Jusangjeolli, and O’sulloc are all fairly manageable for most travelers, while Eoseungsaengak is the one stop that adds real stairs and incline."},{"label":"A good middle ground between passive sightseeing and full trekking","detail":"This route feels more active than a pure coach panorama tour, but it is still far lighter than a dedicated hiking itinerary."},{"label":"Mixed-age groups can usually handle it","detail":"The route works for many mixed-age groups as long as they are comfortable with a short uphill trail at the end."}]},{"title":"When weather changes on site","icon":"cloud-rain","iconBg":"bg-slate-50/80","iconColor":"text-slate-600","items":[{"label":"The coast-heavy first half is weather-sensitive","detail":"Oedolgae, Jusangjeolli, and Eoseungsaengak are the stops most affected by wind, rain, or sudden visibility changes."},{"label":"O’sulloc helps balance poor weather days","detail":"Because O’sulloc includes indoor space and easy circulation, it gives the route some operational flexibility when conditions worsen."},{"label":"Trail control can affect the finish","detail":"If Hallasan-side conditions are restricted, the last stop may need a shortened stay or operational substitution."}]}]},"practicalAccordionItems":[{"id":"pickup","title":"Pickup and Return Times","preview":"4 fixed pickup points + 5 city drop-off points","content":["Pickup: 08:30 Ocean Suites Hotel","Pickup: 08:45 Jeju Airport, 3rd Floor Gate 3","Pickup: 08:55 Lotte City Hotel Jeju","Pickup: 09:05 Shilla Duty Free Shop","Drop-off: Ocean Suites Hotel","Drop-off: Jeju Airport, 3rd Floor Gate 3","Drop-off: Lotte City Hotel Jeju","Drop-off: Shilla Duty Free Shop","Extra drop-off available at Dongmun Market","Expected return to Jeju City around 17:30–18:10 depending on traffic and weather","Please arrive at least 10 minutes early at your selected pickup point"]},{"id":"walking","title":"Walking and Terrain","preview":"Moderate overall, with Eoseungsaengak as the key active stop","content":["Cheonjiyeon is mostly a paved waterfall approach and return walk","Oedolgae and Jusangjeolli are short viewpoint walks with some uneven outdoor surfaces","O’sulloc is easy and relatively relaxed","Eoseungsaengak is the most physically demanding stop because of stairs and uphill sections","Comfortable walking shoes with grip are strongly recommended"]},{"id":"weather","title":"Weather and Route Adjustments","preview":"Most affected by wind on the coast and conditions near Hallasan","content":["Light rain: the tour usually still operates","Heavy rain or strong wind: exposed coastal stops may be shortened","Hallasan-side weather controls can affect Eoseungsaengak access","If a stop becomes unsafe or inaccessible, timing or stop order may be adjusted"]},{"id":"wear","title":"What to Wear and Bring","preview":"Walking shoes, layers, and wind protection are the basics","content":["Comfortable walking shoes with good grip","A light jacket or windproof outer layer","Layered clothing for changing mountain and coast temperatures","Sun protection and a hat","Water bottle"]},{"id":"included","title":"What’s Included / Not Included","preview":"Guide, vehicle, fixed pickup, and standard sightseeing support","variant":"included","content":["Professional English-speaking guide","Shared bus transportation","Fixed pickup and drop-off in Jeju City","Basic guided sightseeing support","Admission fees are not included unless otherwise specified at checkout","Lunch is not included unless otherwise specified","Personal expenses, café purchases, and optional shopping are not included","Guide gratuities are optional"]}],"bookingTrustItems":[{"icon":"check-circle","title":"Fixed Jeju City pickups","description":"Four meeting points with scheduled times","iconBg":"bg-emerald-50/80","iconColor":"text-emerald-600"},{"icon":"route","title":"Structured bus day","description":"Waterfall, cliffs, tea, and Hallasan in one route","iconBg":"bg-sky-50/80","iconColor":"text-sky-600"},{"icon":"users","title":"South & southwest coverage","description":"Classic stops at a bus-tour price point","iconBg":"bg-amber-50/80","iconColor":"text-amber-600"}],"bookingSupportSteps":[{"timing":"預訂時（重要）","title":"留下您實際會用的聯絡方式","detail":"請填寫您平常會查看的手機、WhatsApp、Line ID 或可加好友連結。若聯絡不上，可能無法在前一天完成集合確認。"},{"timing":"預訂後","title":"確認信","detail":"您會先收到預訂確認信，含行程摘要、價格與集合／上車方式說明。"},{"timing":"出發前一日","title":"導遊直接與您聯絡","detail":"出發前一天，導遊會以 WhatsApp、Line 或電話直接聯絡，確認時間、正確集合地點與最後細節。"},{"timing":"行程當天","title":"集合地點","detail":"請至少提前 10 分鐘抵達。巴士準時發車，請以導遊告知的時間為準。"},{"timing":"行程結束後","title":"下車與後續協助","detail":"在濟州市內固定下車點下車。若之後需要協助，請傳訊息給我們。"}],"practicalWeatherStatic":{"today":{"temp":"—","label":"Live weather integration"},"tomorrow":{"temp":"—","label":"Updated daily"}},"seasonalVariations":[{"name":"Spring","icon":"flower","description":"Fresh green tea-field atmosphere and clearer walking weather often improve the O’sulloc and Eoseungsaengak sections.","tag":"Mild weather","bgClass":"bg-spring","iconColor":"text-pink-500"},{"name":"Summer","icon":"sun","description":"Coastal humidity and sun exposure make the morning stops feel brighter but more exposed, while waterfall shade becomes more welcome.","tag":"Lush scenery","bgClass":"bg-summer","iconColor":"text-yellow-500"},{"name":"Autumn","icon":"leaf","description":"Autumn light tends to sharpen the sea-cliff and Hallasan-side views, making this one of the strongest photo seasons for the route.","tag":"Best photo season","bgClass":"bg-autumn","iconColor":"text-orange-500"},{"name":"Winter","icon":"snowflake","description":"Road 1100 and the Eoseungsaengak area can look especially striking in cold weather, but trail control and wind become more important.","tag":"Weather-sensitive","bgClass":"bg-winter","iconColor":"text-sky-500"}],"faqItems":[{"q":"Is this a good South Jeju tour for first-time visitors?","a":"Yes. It covers several of the best-known South Jeju landmarks in one day and keeps the price lower than a private tour, which makes it a strong first-visit bus option."},{"q":"How difficult is the walking on this route?","a":"Most stops are manageable for average travelers. The one stop that clearly feels more active is Eoseungsaengak, which includes stairs and a short uphill trail."},{"q":"Are admission tickets included?","a":"This JSON is structured for a bus-tour setup where admission is not included unless your checkout configuration says otherwise. Keep the live product setup aligned with your actual offer."},{"q":"Can the route change in bad weather?","a":"Yes. Wind, heavy rain, and Hallasan-side access controls can affect the route, especially the exposed coastal stops and Eoseungsaengak."},{"question":"Is lunch included?","answer":"The itinerary includes a one-hour lunch break after Jusangjeolli Cliff. Lunch is free choice, and meal costs are not included in the tour price."}],"reviewsPreview":{"averageRating":4.7,"totalReviews":89,"highlights":[{"label":"Scenery","count":61},{"label":"Value","count":44},{"label":"Guide","count":39},{"label":"Route mix","count":33}],"featured":[{"name":"Olivia","country":"United Kingdom","rating":5,"comment":"A very efficient way to see several classic South Jeju stops in one day. The route felt varied, and O’sulloc gave the day a nice break from pure lookout stops.","tripType":"Couple"},{"name":"Daniel","country":"United States","rating":4,"comment":"Good value for a bus tour. Eoseungsaengak was the most active part, but the rest felt manageable and well spaced out.","tripType":"Family"}]},"stickyBooking":{"price":{"amountLabel":"49","currency":"USD","per":"person"}},"matching_profile":{"product_id":"south-jeju-classic-bus-tour","product_type":"bus","route_type":"fixed_route","region_type":"southwest","region_tags":["jeju_south","jeju_southwest","jungmun","hallasan_1100"],"theme_tags":["waterfall","coast","basalt_cliff","tea","hallasan","first_time_friendly","iconic_landmarks","value_route"],"poi_tags":["cheonjiyeon_waterfall","oedolgae","jusangjeolli_cliff","osulloc_tea_museum","eoseungsaengak"],"pace_level":4,"walking_level":3,"scenic_level":5,"photo_level":5,"culture_level":2,"relax_level":3,"first_time_fit":5,"family_fit":4,"senior_fit":3,"couple_fit":4,"active_traveler_fit":4,"one_day_fit":4,"same_day_flight_fit":2,"rain_fit":2,"value_for_money_fit":5,"iconic_landmark_fit":4,"cafe_fit":3,"adult_family_fit":4,"young_kids_fit":3,"senior_active_fit":4,"senior_general_fit":3,"mobility_friendly_fit":2,"stroller_fit":2,"indoor_ratio":26,"weather_sensitivity":4,"local_culture_fit":2,"shopping_fit":2,"storytelling_fit":3,"comfort_level":3,"budget_fit":5,"premium_fit":1,"small_group_fit":1,"private_fit":1,"bus_fit":5,"price_band":"budget","pickup_base":"jeju_city","return_time_band":"17:30-18:10","duration_band":"9h","min_recommended_age":7,"hard_constraints":{"avoidIf":["high_wind_hallasan_or_coast_alert","travelers_needing_a_slow_luxury_pace"],"notIdealFor":["very_low_mobility","stroller_heavy_on_trail","travelers_avoiding_stairs"]},"walking_notes":["Overall walking is moderate for a bus tour rather than a trekking tour.","Cheonjiyeon, Oedolgae, Jusangjeolli, and O’sulloc are manageable for most travelers.","Eoseungsaengak is the steepest and most physically demanding stop because of stairs and uphill sections.","Comfortable grip shoes are strongly recommended, especially in wet or windy weather."],"keywords":["south jeju bus tour","jeju south waterfall cliff tea tour","cheonjiyeon oedolgae jusangjeolli osulloc","eoseungsaengak bus day tour","best value jeju bus tour","first time south jeju day trip","southwest jeju sightseeing bus","jeju tea museum day tour","hallasan short trail bus tour","south jeju classic route"],"synonym_hints":["classic south jeju bus route","south jeju highlights by bus","waterfall cliff tea field day","budget-friendly jeju south tour","south coast plus hallasan light hike","fixed pickup jeju bus tour"],"profile_version":1,"is_active":true},"matching_metadata":{"matching_schema":"tour_matching_profiles_embedded_v1","embedded_for":["authoring","review","sql_backfill_reference"],"note":"Scores were tuned for a classic Jeju bus-tour format: high scenic and value fit, moderate walking overall, and lower rain/mobility scores because of exposed coastal stops plus the Eoseungsaengak finish.","duration_hours":10,"stop_count":6},"pickup_dropoff":{"pickupType":"fixed_meeting_points","dropoffType":"fixed_dropoff_points","departure":[{"order":1,"time":"08:30","name":"Ocean Suites Hotel","type":"hotel","note":"Main city pickup point near Tapdong."},{"order":2,"time":"08:45","name":"Jeju Airport, 3rd Floor Gate 3","type":"airport","note":"Departure floor meeting point."},{"order":3,"time":"08:55","name":"Lotte City Hotel Jeju","type":"hotel","note":"Central Jeju City hotel pickup point."},{"order":4,"time":"09:05","name":"Shilla Duty Free Shop","type":"shopping","note":"Popular downtown meeting point."}],"return":[{"order":1,"name":"Ocean Suites Hotel","type":"hotel","note":"Standard city drop-off point."},{"order":2,"name":"Jeju Airport, 3rd Floor Gate 3","type":"airport","note":"Useful for same-day departures; exact stop order may vary."},{"order":3,"name":"Lotte City Hotel Jeju","type":"hotel","note":"Standard city drop-off point."},{"order":4,"name":"Shilla Duty Free Shop","type":"shopping","note":"Standard city drop-off point."},{"order":5,"name":"Dongmun Market","type":"market","note":"Additional downtown drop-off for travelers who want to continue the evening in central Jeju City."}],"notes":["Return usually runs around 17:30–18:10 depending on traffic, weather, and day-of-road conditions.","Drop-off order may be adjusted slightly for operational efficiency.","Please arrive at least 10 minutes early at your selected pickup point."]}}'::jsonb
)
